Resource: aws_wafv2_web_acl.cloudfront
File: /waf.tf: 147-183
Guideline: https://docs.prismacloud.io/en/enterprise-edition/policy-reference/aws-policies/aws-networking-policies/ensure-waf-prevents-message-lookup-in-log4j2

		147 | resource "aws_wafv2_web_acl" "cloudfront" {
		148 |   provider    = aws.us_east_1
		149 |   name        = "${var.project_name}-waf-cloudfront"
		150 |   scope       = "CLOUDFRONT"
		151 |   description = "WAF para proteger la distribucion CloudFront de SEGAT"
		152 | 
		153 |   default_action {
		154 |     allow {}
		155 |   }
		156 | 
		157 |   rule {
		158 |     name     = "AWSManagedRulesCommonRuleSet"
		159 |     priority = 1
		160 |     override_action {
		161 |       none {}
		162 |     }
		163 |     statement {
		164 |       managed_rule_group_statement {
		165 |         name        = "AWSManagedRulesCommonRuleSet"
		166 |         vendor_name = "AWS"
		167 |       }
		168 |     }
		169 |     visibility_config {
		170 |       cloudwatch_metrics_enabled = true
		171 |       metric_name                = "${var.project_name}CloudFrontCommonRuleSetMetric"
		172 |       sampled_requests_enabled   = true
		173 |     }
		174 |   }
		175 | 
		176 |   visibility_config {
		177 |     cloudwatch_metrics_enabled = true
		178 |     metric_name                = "${var.project_name}CloudFrontWAFMetric"
		179 |     sampled_requests_enabled   = true
		180 |   }
		181 | 
		182 |   tags = { Name = "${var.project_name}-waf-cloudfront" }
		183 | }

